parameters.jsCode:
const patients = $json.patients ?? [];
const now = Date.now();

// Filter to patients with high drop-off probability
const atRisk = patients.filter(p => {
  if (!p.churnRisk) return false;
  const lastSession = p.lastSessionDate ? new Date(p.lastSessionDate).getTime() : null;
  const daysSince = lastSession ? Math.floor((now - lastSession) / 86_400_000) : null;
  return daysSince === null || daysSince >= 14;
});

return atRisk.map(p => {
  const lastSession = p.lastSessionDate ? new Date(p.lastSessionDate).getTime() : null;
  const daysSince = lastSession ? Math.floor((now - lastSession) / 86_400_000) : null;

  // Risk level: amber = 14–28 days, red = >28 days
  const riskLevel = daysSince !== null && daysSince > 28 ? 'red' : 'amber';

  return {
    patientId: p.id,
    patientName: p.name,
    patientPhone: p.contact?.phone ?? null,
    patientEmail: p.contact?.email ?? null,
    clinicianName: p.clinicianName ?? 'their physiotherapist',
    daysSinceLastSession: daysSince,
    sessionCount: p.sessionCount,
    riskLevel,
    clinicId: p.clinicId ?? $env.RETELL_CLINIC_ID,
  };
});

